// CustTable table extension
[ExtensionOf(tableStr(CustTable))]
final class CustTable_Extension
{
    [Display("Credit utilization %")]
    public display Percent creditUtilizationPct()
    {
        CustTrans       custTrans;
        AmountMST       totalBalance = 0;
        CreditMax       creditLimit;
        Percent         utilizationPct = 0;

        try
        {
            creditLimit = this.creditMax();
            if (creditLimit == 0)
            {
                return 0; // Avoid division by zero
            }

            // Sum outstanding balance from CustTrans
            select sum(AmountMST) from custTrans
                where custTrans.AccountNum == this.AccountNum
                   && custTrans.Closed == NoYes::No;

            totalBalance = custTrans.AmountMST;
            utilizationPct = (abs(totalBalance) * 100) / creditLimit;

            return min(utilizationPct, 999.99); // Cap at 999.99%
        }
        catch (Exception::Error)
        {
            error("Error calculating credit utilization for customer %1", this.AccountNum);
            return 0;
        }
    }

    [Display("Payment terms description")]
    public display PaymTermDescription paymentTermsDesc()
    {
        PaymTerm paymTerm;

        if (!this.PaymTermId)
        {
            return "";
        }

        select firstonly Description from paymTerm
            where paymTerm.PaymTermId == this.PaymTermId;

        return paymTerm.Description;
    }
}

// SalesTable table extension
[ExtensionOf(tableStr(SalesTable))]
final class SalesTable_Extension
{
    [Edit("Delivery window days")]
    public edit Days deliveryWindowDays(boolean _set = false, Days _days = 0)
    {
        CustTable       custTable;
        InventSiteId    siteId;

        if (_set)
        {
            if (_days < 0)
            {
                throw error("Delivery window cannot be negative");
            }

            if (_days > 365)
            {
                throw error("Delivery window cannot exceed 365 days");
            }

            // Validate against customer's delivery requirements
            custTable = CustTable::find(this.CustAccount);
            if (custTable.DlvModeId)
            {
                DlvMode dlvMode = DlvMode::find(custTable.DlvModeId);
                if (_days > dlvMode.MaxDeliveryDays && dlvMode.MaxDeliveryDays > 0)
                {
                    throw error("Delivery window exceeds maximum allowed for delivery mode %1 (%2 days)",
                              dlvMode.Code, dlvMode.MaxDeliveryDays);
                }
            }

            // Store in a custom field (assumes DeliveryWindowDays field exists)
            this.DeliveryWindowDays = _days;

            // Auto-calculate delivery date if shipping date exists
            if (this.ShippingDateRequested != dateNull())
            {
                this.DeliveryDate = this.ShippingDateRequested + _days;
                info("Delivery date automatically updated to %1", this.DeliveryDate);
            }

            // Validate field to trigger any additional validation
            this.validateField(fieldNum(SalesTable, DeliveryWindowDays));
        }

        return this.DeliveryWindowDays;
    }

    [Edit("Priority level")]
    public edit str priorityLevel(boolean _set = false, str _priority = "")
    {
        Priority    priorityEnum;

        if (_set)
        {
            _priority = strUpr(strLTrim(strRTrim(_priority)));

            switch (_priority)
            {
                case "HIGH", "URGENT", "1":
                    priorityEnum = Priority::High;
                    break;
                case "MEDIUM", "NORMAL", "2":
                    priorityEnum = Priority::Medium;
                    break;
                case "LOW", "3":
                    priorityEnum = Priority::Low;
                    break;
                default:
                    throw error("Invalid priority level. Use HIGH, MEDIUM, or LOW");
            }

            this.Priority = priorityEnum;

            // Trigger dependent field updates
            this.modifiedField(fieldNum(SalesTable, Priority));
        }

        // Return string representation
        switch (this.Priority)
        {
            case Priority::High:
                return "HIGH";
            case Priority::Medium:
                return "MEDIUM";
            case Priority::Low:
                return "LOW";
            default:
                return "UNDEFINED";
        }
    }
}

// VendTable table extension with static caching
[ExtensionOf(tableStr(VendTable))]
final class VendTable_Extension
{
    private static Map vendorOrderCountCache;
    private static utcdatetime cacheTimestamp;
    private static int cacheDurationMinutes = 15;

    [Display("Open PO count")]
    public display Integer openPurchOrderCount()
    {
        PurchTable      purchTable;
        Integer         orderCount = 0;
        utcdatetime     currentTime = DateTimeUtil::utcNow();

        // Initialize cache if not exists
        if (!vendorOrderCountCache)
        {
            vendorOrderCountCache = new Map(Types::String, Types::Integer);
            cacheTimestamp = currentTime;
        }

        // Check cache expiry
        if (DateTimeUtil::getDifference(currentTime, cacheTimestamp) > (cacheDurationMinutes * 60))
        {
            vendorOrderCountCache.empty();
            cacheTimestamp = currentTime;
        }

        // Check cache first
        if (vendorOrderCountCache.exists(this.AccountNum))
        {
            return vendorOrderCountCache.lookup(this.AccountNum);
        }

        try
        {
            select count(RecId) from purchTable
                where purchTable.OrderAccount == this.AccountNum
                   && purchTable.PurchStatus == PurchStatus::Backorder;

            orderCount = purchTable.RecId;

            // Cache the result
            vendorOrderCountCache.insert(this.AccountNum, orderCount);
        }
        catch (Exception::Error)
        {
            warning("Unable to retrieve purchase order count for vendor %1", this.AccountNum);
            orderCount = -1; // Indicate error state
        }

        return orderCount;
    }

    // Static method to preload cache for multiple vendors (call from form init)
    public static void preloadOrderCounts(Set _vendorAccounts)
    {
        PurchTable      purchTable;
        VendAccount     vendorAccount;
        SetEnumerator   enumerator;
        Map             countMap = new Map(Types::String, Types::Integer);

        if (!_vendorAccounts || _vendorAccounts.elements() == 0)
        {
            return;
        }

        // Batch query to get all counts at once
        while select OrderAccount, count(RecId) from purchTable
            group by OrderAccount
            where purchTable.PurchStatus == PurchStatus::Backorder
        {
            if (_vendorAccounts.in(purchTable.OrderAccount))
            {
                countMap.insert(purchTable.OrderAccount, purchTable.RecId);
            }
        }

        // Initialize cache with results
        vendorOrderCountCache = countMap;
        cacheTimestamp = DateTimeUtil::utcNow();

        info("Preloaded purchase order counts for %1 vendors", countMap.elements());
    }

    // Method to invalidate cache when PO data changes
    public static void invalidateOrderCountCache(VendAccount _vendorAccount = "")
    {
        if (!vendorOrderCountCache)
        {
            return;
        }

        if (_vendorAccount)
        {
            vendorOrderCountCache.remove(_vendorAccount);
        }
        else
        {
            vendorOrderCountCache.empty();
        }
    }
}
